/**
 * Dev Dito Plugin - Frontend JavaScript
 * Provides semantic search interface for wiki content
 */
(function() {
  'use strict';

  // Wait for DOM ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initDevDito);
  } else {
    initDevDito();
  }

  function initDevDito() {
    var panel = document.getElementById('devdito-panel');
    var toggleBtn = document.getElementById('devdito-toggle');

    if (!panel || !toggleBtn) {
      console.warn('[DevDito] Panel or toggle button not found');
      return;
    }

    var mcpUrl = panel.dataset.mcpUrl || '';
    var isOpen = false;
    var isSearching = false;

    // Build panel UI
    buildPanelUI(panel);

    // Toggle button click handler
    toggleBtn.addEventListener('click', function(e) {
      e.preventDefault();
      togglePanel();
    });

    // Keyboard shortcut: Ctrl+Shift+F to toggle
    document.addEventListener('keydown', function(e) {
      if (e.ctrlKey && e.shiftKey && e.key === 'F') {
        e.preventDefault();
        togglePanel();
      }
    });

    function togglePanel() {
      isOpen = !isOpen;
      panel.setAttribute('aria-hidden', isOpen ? 'false' : 'true');
      toggleBtn.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
      
      if (isOpen) {
        // Focus search input when opening
        var searchInput = document.getElementById('devdito-search-input');
        if (searchInput) {
          setTimeout(function() { searchInput.focus(); }, 100);
        }
      }
    }

    function buildPanelUI(panel) {
      panel.innerHTML = [
        '<div id="devdito-header">',
        '  <h3>Dev Dito - Wiki Suche</h3>',
        '  <button id="devdito-close" type="button" aria-label="Panel schliessen" title="Schliessen">x</button>',
        '</div>',
        '<div id="devdito-search-form">',
        '  <input type="text" id="devdito-search-input" placeholder="Suchbegriff eingeben..." autocomplete="off">',
        '  <button type="button" id="devdito-search-btn">Suchen</button>',
        '</div>',
        '<div id="devdito-results">',
        '  <p class="devdito-no-results">Geben Sie einen Suchbegriff ein und klicken Sie auf "Suchen".</p>',
        '</div>'
      ].join('\n');

      // Close button handler
      var closeBtn = document.getElementById('devdito-close');
      if (closeBtn) {
        closeBtn.addEventListener('click', function() {
          isOpen = false;
          panel.setAttribute('aria-hidden', 'true');
          toggleBtn.setAttribute('aria-expanded', 'false');
        });
      }

      // Search form handlers
      var searchInput = document.getElementById('devdito-search-input');
      var searchBtn = document.getElementById('devdito-search-btn');

      if (searchInput && searchBtn) {
        // Enter key triggers search
        searchInput.addEventListener('keydown', function(e) {
          if (e.key === 'Enter') {
            e.preventDefault();
            performSearch();
          }
        });

        // Search button click
        searchBtn.addEventListener('click', function() {
          performSearch();
        });
      }
    }

    function performSearch() {
      if (isSearching) return;

      var searchInput = document.getElementById('devdito-search-input');
      var searchBtn = document.getElementById('devdito-search-btn');
      var resultsDiv = document.getElementById('devdito-results');

      var query = searchInput ? searchInput.value.trim() : '';
      if (!query) {
        resultsDiv.innerHTML = '<p class="devdito-error">Bitte geben Sie einen Suchbegriff ein.</p>';
        return;
      }

      isSearching = true;
      searchBtn.disabled = true;
      searchBtn.textContent = 'Suche...';
      resultsDiv.innerHTML = '<div class="devdito-loading"><span class="devdito-spinner"></span> Suche laeuft...</div>';

      // Make AJAX request
      var xhr = new XMLHttpRequest();
      xhr.open('POST', DOKU_BASE + 'lib/exe/ajax.php?call=devdito_search', true);
      xhr.setRequestHeader('Content-Type', 'application/json');
      xhr.timeout = 30000;

      xhr.onload = function() {
        isSearching = false;
        searchBtn.disabled = false;
        searchBtn.textContent = 'Suchen';

        if (xhr.status === 200) {
          try {
            var response = JSON.parse(xhr.responseText);
            displayResults(response, query);
          } catch (e) {
            resultsDiv.innerHTML = '<p class="devdito-error">Fehler beim Parsen der Antwort.</p>';
          }
        } else {
          resultsDiv.innerHTML = '<p class="devdito-error">Suche fehlgeschlagen (HTTP ' + xhr.status + ')</p>';
        }
      };

      xhr.onerror = function() {
        isSearching = false;
        searchBtn.disabled = false;
        searchBtn.textContent = 'Suchen';
        resultsDiv.innerHTML = '<p class="devdito-error">Netzwerkfehler bei der Suche.</p>';
      };

      xhr.ontimeout = function() {
        isSearching = false;
        searchBtn.disabled = false;
        searchBtn.textContent = 'Suchen';
        resultsDiv.innerHTML = '<p class="devdito-error">Zeituberschreitung bei der Suche.</p>';
      };

      xhr.send(JSON.stringify({ query: query, limit: 5 }));
    }

    function displayResults(response, query) {
      var resultsDiv = document.getElementById('devdito-results');

      if (!response.ok) {
        var errorMsg = response.error || 'unknown_error';
        var errorText = {
          'mcp_url_not_configured': 'MCP Server URL nicht konfiguriert.',
          'query_empty': 'Leere Suchanfrage.',
          'search_failed': 'Suche fehlgeschlagen.',
          'invalid_json': 'Ungueltige Server-Antwort.',
          'rpc_error': response.message || 'RPC Fehler.'
        }[errorMsg] || errorMsg;
        
        resultsDiv.innerHTML = '<p class="devdito-error">' + escapeHtml(errorText) + '</p>';
        return;
      }

      // Parse the raw content (markdown-formatted results)
      var content = response.raw_content || '';
      
      if (!content || content.indexOf('Keine Ergebnisse') !== -1 || content.indexOf('0 Ergebnisse') !== -1) {
        resultsDiv.innerHTML = '<p class="devdito-no-results">Keine Ergebnisse gefunden fuer "' + escapeHtml(query) + '"</p>';
        return;
      }

      // Parse results from markdown content
      var results = parseMarkdownResults(content);
      
      if (results.length === 0) {
        resultsDiv.innerHTML = '<p class="devdito-no-results">Keine Ergebnisse gefunden fuer "' + escapeHtml(query) + '"</p>';
        return;
      }

      // Build results HTML
      var html = '<p style="font-size:12px;color:#6b7280;margin-bottom:12px;">Gefunden: ' + results.length + ' Ergebnisse (' + (response.latency_ms || 0) + 'ms)</p>';
      
      results.forEach(function(result) {
        html += '<div class="devdito-result">';
        html += '<div class="devdito-result-title">';
        if (result.url) {
          html += '<a href="' + escapeHtml(result.url) + '" target="_blank">' + escapeHtml(result.title || 'Unbekannt') + '</a>';
        } else {
          html += escapeHtml(result.title || 'Unbekannt');
        }
        html += '</div>';
        if (result.score) {
          html += '<div class="devdito-result-score">Score: ' + result.score + '</div>';
        }
        if (result.namespace) {
          html += '<div class="devdito-result-score">Namespace: ' + escapeHtml(result.namespace) + '</div>';
        }
        if (result.text) {
          // Truncate text
          var text = result.text.length > 300 ? result.text.substring(0, 300) + '...' : result.text;
          html += '<div class="devdito-result-text">' + escapeHtml(text) + '</div>';
        }
        html += '</div>';
      });

      resultsDiv.innerHTML = html;
    }

    function parseMarkdownResults(content) {
      var results = [];
      
      // Split by result headers (### 1. Title (Score: 0.xxx))
      var resultBlocks = content.split(/###\s+\d+\.\s+/);
      
      resultBlocks.forEach(function(block) {
        if (!block.trim()) return;
        
        var result = {};
        
        // Extract title and score from first line
        var firstLineMatch = block.match(/^(.+?)\s*\(Score:\s*([\d.]+)\)/);
        if (firstLineMatch) {
          result.title = firstLineMatch[1].trim();
          result.score = firstLineMatch[2];
        } else {
          // Try to get title from first line
          var lines = block.split('\n');
          if (lines[0]) {
            result.title = lines[0].replace(/\(Score:.*\)/, '').trim();
          }
        }
        
        // Extract namespace
        var nsMatch = block.match(/\*\*Namespace:\*\*\s*(.+)/);
        if (nsMatch) result.namespace = nsMatch[1].trim();
        
        // Extract URL
        var urlMatch = block.match(/\*\*URL:\*\*\s*(.+)/);
        if (urlMatch) result.url = urlMatch[1].trim();
        
        // Extract page ID
        var pageIdMatch = block.match(/\*\*Seiten-ID:\*\*\s*(.+)/);
        if (pageIdMatch) result.pageId = pageIdMatch[1].trim();
        
        // Extract text content (everything after the metadata)
        var textMatch = block.match(/---[\s\S]*?\n([\s\S]+?)(?=\n---|$)/);
        if (!textMatch) {
          // Try to get content after metadata lines
          var contentStart = block.indexOf('\n\n');
          if (contentStart > 0) {
            result.text = block.substring(contentStart).replace(/\*\*[^*]+:\*\*[^\n]+/g, '').trim();
          }
        } else {
          result.text = textMatch[1].trim();
        }
        
        if (result.title) {
          results.push(result);
        }
      });
      
      return results;
    }

    function escapeHtml(text) {
      var div = document.createElement('div');
      div.textContent = text;
      return div.innerHTML;
    }
  }
})();
